using Microsoft.ML.Data;

namespace TicketClassifier.Models;

/// <summary>
/// Raw ticket data loaded from CSV or submitted via API.
/// </summary>
public sealed class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

/// <summary>
/// ML.NET prediction output.
/// </summary>
public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

/// <summary>
/// API request body for the /predict endpoint.
/// </summary>
public sealed class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

/// <summary>
/// API response from the /predict endpoint.
/// </summary>
public sealed class TicketResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

/// <summary>
/// Evaluation metrics returned by the /metrics endpoint.
/// </summary>
public sealed class EvaluationMetrics
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketInput, TicketPrediction> _predictionEngine;
    private readonly EvaluationMetrics _metrics;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        // Load data
        IDataView dataView = _mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Build the training pipeline:
        // 1. Combine Subject + Description into a single text feature
        // 2. Featurize the combined text
        // 3. Include Priority as a numeric feature
        // 4. Concatenate all features
        // 5. Map Category string to a key for the trainer
        // 6. Train with SDCA (multi-class)
        // 7. Map the predicted key back to a string label
        var pipeline = _mlContext.Transforms.CustomMapping<TicketInput, CombinedText>(
                (input, output) => output.Text = $"{input.Subject} {input.Description}",
                contractName: "CombineText")
            .Append(_mlContext.Transforms.Text.FeaturizeText("TextFeatures", nameof(CombinedText.Text)))
            .Append(_mlContext.Transforms.Concatenate("Features", "TextFeatures", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Train
        _model = pipeline.Fit(dataView);

        // Evaluate (using training data — small dataset, so no split)
        IDataView predictions = _model.Transform(dataView);
        var evalMetrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");
        _metrics = new EvaluationMetrics
        {
            MacroAccuracy = evalMetrics.MacroAccuracy,
            MicroAccuracy = evalMetrics.MicroAccuracy,
            LogLoss = evalMetrics.LogLoss,
            LogLossReduction = evalMetrics.LogLossReduction,
        };

        // Cache category labels in slot order for confidence mapping
        var schema = _model.GetOutputSchema(dataView.Schema);
        var scoreColumn = schema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        _categoryLabels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketInput, TicketPrediction>(_model);
    }

    public (TicketPrediction Prediction, Dictionary<string, float> Confidence) Predict(TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionEngine.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _categoryLabels.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return (prediction, confidence);
    }

    public EvaluationMetrics GetMetrics() => _metrics;
}

/// <summary>Helper class for the custom mapping step.</summary>
public sealed class CombinedText
{
    public string Text { get; set; } = string.Empty;
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController(TicketClassifierService classifierService) : ControllerBase
{
    /// <summary>
    /// Predict the category for a support ticket.
    /// </summary>
    [HttpPost("predict")]
    public ActionResult<TicketResponse> Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description must be provided.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var (prediction, confidence) = classifierService.Predict(request);

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence,
        });
    }

    /// <summary>
    /// Return model evaluation metrics from the training run.
    /// </summary>
    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> GetMetrics()
    {
        return Ok(classifierService.GetMetrics());
    }
}

